# solution.py
"""SportGame_Collaborative_Analytics / Team_Collaboration_Manager.

A thread-safe, in-memory collaboration backend that lets multiple analysts
(users) work simultaneously on shared projects.  It supports user accounts,
projects, tasks, threaded messaging with attachments, performance dashboards,
ratings, and exportable reports (CSV / PDF).

All public mutating and reading operations are serialized through a single
shared re-entrant lock so that concurrent agents observe a consistent view of
the data.  Every entity returned to a caller is a deep copy, so external
mutation can never corrupt the internal store.

Standard library only.
"""

import csv
import io
import threading
from copy import deepcopy
from dataclasses import dataclass, field
from datetime import datetime
from enum import Enum
from typing import Any, Dict, List, Optional


# ---------------------------------------------------------------------------
# Enumerations
# ---------------------------------------------------------------------------
class UserRole(Enum):
    """Access role for a user account."""

    MEMBER = "member"
    ADMIN = "admin"


class TaskStatus(Enum):
    """Lifecycle status for a task."""

    NOT_STARTED = "not_started"
    IN_PROGRESS = "in_progress"
    COMPLETED = "completed"


class ReportFormat(Enum):
    """Export formats supported by :meth:`TeamCollaborationManager.export_report`."""

    CSV = "csv"
    PDF = "pdf"


class ReportType(Enum):
    """Identifies the shape of a generated report dictionary."""

    PROJECT_PROGRESS = "project_progress"
    TEAM_PERFORMANCE = "team_performance"
    INDIVIDUAL_PERFORMANCE = "individual_performance"


# ---------------------------------------------------------------------------
# Exception hierarchy
# ---------------------------------------------------------------------------
class TeamCollaborationError(Exception):
    """Base class for all errors raised by the manager."""


class ValidationError(TeamCollaborationError):
    """Raised when input fails validation."""


class NotFoundError(TeamCollaborationError):
    """Raised when a referenced entity does not exist."""


class AuthorizationError(TeamCollaborationError):
    """Raised when an actor is not permitted to perform an action."""


class DuplicateError(TeamCollaborationError):
    """Raised when a uniqueness constraint is violated."""


class ConflictError(TeamCollaborationError):
    """Raised when an operation conflicts with current state."""


# ---------------------------------------------------------------------------
# Data models
# ---------------------------------------------------------------------------
@dataclass
class User:
    id: int
    username: str
    email: str
    role: UserRole
    created_at: datetime


@dataclass
class Project:
    id: int
    name: str
    description: str
    start_date: datetime
    end_date: datetime
    owner_id: int


@dataclass
class Task:
    id: int
    project_id: int
    title: str
    status: TaskStatus
    assignee_id: Optional[int] = None
    deadline: Optional[datetime] = None
    started_at: Optional[datetime] = None
    completed_at: Optional[datetime] = None
    created_at: Optional[datetime] = None


@dataclass
class Attachment:
    filename: str
    size: int
    uploaded_by: int
    uploaded_at: datetime


@dataclass
class Message:
    id: int
    author_id: int
    body: str
    project_id: Optional[int] = None
    task_id: Optional[int] = None
    parent_id: Optional[int] = None
    attachments: List[Attachment] = field(default_factory=list)
    created_at: Optional[datetime] = None
    edited_at: Optional[datetime] = None


@dataclass
class Rating:
    id: int
    rater_id: int
    ratee_id: int
    score: int
    feedback: str = ""
    task_id: Optional[int] = None
    created_at: Optional[datetime] = None


# ---------------------------------------------------------------------------
# Internal store
# ---------------------------------------------------------------------------
class _Store:
    """A simple data holder that shares a lock with its siblings.

    Each store keeps a primary ``_items`` mapping plus a handful of secondary
    indexes.  Not all indexes are used by every store; unused ones simply stay
    empty.  The ``_lock`` is the *same object* across every store and the owning
    manager, which lets the test-suite assert shared-lock identity.
    """

    def __init__(self, lock):
        self._lock = lock
        self._items: Dict[int, Any] = {}
        self._by_project: Dict[int, List[int]] = {}
        self._by_assignee: Dict[int, List[int]] = {}
        self._by_task: Dict[int, List[int]] = {}
        self._by_ratee: Dict[int, List[int]] = {}


# ---------------------------------------------------------------------------
# Manager
# ---------------------------------------------------------------------------
class TeamCollaborationManager:
    """Orchestrates collaborative analytics data for a team of analysts."""

    def __init__(self, now=None):
        # A single re-entrant lock shared by the manager and every sub-store.
        self._lock = threading.RLock()
        self._now = now if now is not None else datetime.now
        self._id_counter = 0

        self.users = _Store(self._lock)
        self.projects = _Store(self._lock)
        self.tasks = _Store(self._lock)
        self.messages = _Store(self._lock)
        self.performance = _Store(self._lock)
        self.reports = _Store(self._lock)

        # Uniqueness indexes for user accounts.
        self._username_index: Dict[str, int] = {}
        self._email_index: Dict[str, int] = {}

    # -- internal helpers --------------------------------------------------
    def _clock(self) -> datetime:
        return self._now()

    def _next_id(self) -> int:
        self._id_counter += 1
        return self._id_counter

    def _get_user_raw(self, user_id) -> User:
        user = self.users._items.get(user_id)
        if user is None:
            raise NotFoundError("user {0} not found".format(user_id))
        return user

    def _get_project_raw(self, project_id) -> Project:
        project = self.projects._items.get(project_id)
        if project is None:
            raise NotFoundError("project {0} not found".format(project_id))
        return project

    def _get_task_raw(self, task_id) -> Task:
        task = self.tasks._items.get(task_id)
        if task is None:
            raise NotFoundError("task {0} not found".format(task_id))
        return task

    def _get_message_raw(self, message_id) -> Message:
        msg = self.messages._items.get(message_id)
        if msg is None:
            raise NotFoundError("message {0} not found".format(message_id))
        return msg

    @staticmethod
    def _validate_email(email) -> None:
        if not isinstance(email, str) or not email.strip():
            raise ValidationError("email must be a non-empty string")
        if "@" not in email:
            raise ValidationError("email must contain '@'")

    @staticmethod
    def _validate_non_empty(value, label) -> None:
        if not isinstance(value, str) or not value.strip():
            raise ValidationError("{0} must be a non-empty string".format(label))

    def _set_assignee(self, task: Task, assignee_id) -> None:
        """Move a task between assignee indexes (lock must be held)."""
        old = task.assignee_id
        if old is not None:
            bucket = self.tasks._by_assignee.get(old)
            if bucket and task.id in bucket:
                bucket.remove(task.id)
        task.assignee_id = assignee_id
        if assignee_id is not None:
            self.tasks._by_assignee.setdefault(assignee_id, []).append(task.id)

    def _purge_message(self, message_id) -> None:
        msg = self.messages._items.pop(message_id, None)
        if msg is None:
            return
        if msg.project_id is not None:
            bucket = self.messages._by_project.get(msg.project_id)
            if bucket and message_id in bucket:
                bucket.remove(message_id)
        if msg.task_id is not None:
            bucket = self.messages._by_task.get(msg.task_id)
            if bucket and message_id in bucket:
                bucket.remove(message_id)

    def _purge_task(self, task: Task) -> None:
        tid = task.id
        self.tasks._items.pop(tid, None)
        bucket = self.tasks._by_project.get(task.project_id)
        if bucket and tid in bucket:
            bucket.remove(tid)
        if task.assignee_id is not None:
            bucket = self.tasks._by_assignee.get(task.assignee_id)
            if bucket and tid in bucket:
                bucket.remove(tid)
        for mid in list(self.messages._by_task.get(tid, [])):
            self._purge_message(mid)
        self.messages._by_task.pop(tid, None)

    # ------------------------------------------------------------------
    # User management
    # ------------------------------------------------------------------
    def register_user(self, username, email, role=UserRole.MEMBER) -> User:
        with self._lock:
            self._validate_non_empty(username, "username")
            self._validate_email(email)
            if not isinstance(role, UserRole):
                raise ValidationError("role must be a UserRole")
            if username in self._username_index:
                raise DuplicateError("username already taken")
            if email in self._email_index:
                raise DuplicateError("email already taken")

            user = User(
                id=self._next_id(),
                username=username,
                email=email,
                role=role,
                created_at=self._clock(),
            )
            self.users._items[user.id] = user
            self._username_index[username] = user.id
            self._email_index[email] = user.id
            return deepcopy(user)

    def get_user(self, user_id) -> User:
        with self._lock:
            return deepcopy(self._get_user_raw(user_id))

    def list_users(self) -> List[User]:
        with self._lock:
            items = sorted(self.users._items.values(), key=lambda u: u.id)
            return [deepcopy(u) for u in items]

    def update_user(self, user_id, username=None, email=None, role=None) -> User:
        with self._lock:
            user = self._get_user_raw(user_id)

            if username is not None:
                self._validate_non_empty(username, "username")
                owner = self._username_index.get(username)
                if owner is not None and owner != user_id:
                    raise DuplicateError("username already taken")
            if email is not None:
                self._validate_email(email)
                owner = self._email_index.get(email)
                if owner is not None and owner != user_id:
                    raise DuplicateError("email already taken")
            if role is not None and not isinstance(role, UserRole):
                raise ValidationError("role must be a UserRole")

            if username is not None and username != user.username:
                self._username_index.pop(user.username, None)
                self._username_index[username] = user_id
                user.username = username
            if email is not None and email != user.email:
                self._email_index.pop(user.email, None)
                self._email_index[email] = user_id
                user.email = email
            if role is not None:
                user.role = role
            return deepcopy(user)

    def delete_user(self, user_id) -> None:
        with self._lock:
            user = self._get_user_raw(user_id)

            for project in self.projects._items.values():
                if project.owner_id == user_id:
                    raise ConflictError("user owns a project")

            assigned = self.tasks._by_assignee.get(user_id, [])
            for tid in assigned:
                task = self.tasks._items.get(tid)
                if task is not None and task.status != TaskStatus.COMPLETED:
                    raise ConflictError("user has open tasks assigned")

            # Detach any remaining (completed) tasks from this assignee.
            for tid in list(self.tasks._by_assignee.get(user_id, [])):
                task = self.tasks._items.get(tid)
                if task is not None:
                    task.assignee_id = None
            self.tasks._by_assignee.pop(user_id, None)

            self._username_index.pop(user.username, None)
            self._email_index.pop(user.email, None)
            del self.users._items[user_id]

    # ------------------------------------------------------------------
    # Project management
    # ------------------------------------------------------------------
    def create_project(self, name, start_date, end_date, owner_id, description="") -> Project:
        with self._lock:
            self._validate_non_empty(name, "name")
            if end_date < start_date:
                raise ValidationError("end_date cannot precede start_date")
            self._get_user_raw(owner_id)

            project = Project(
                id=self._next_id(),
                name=name,
                description=description,
                start_date=start_date,
                end_date=end_date,
                owner_id=owner_id,
            )
            self.projects._items[project.id] = project
            self.tasks._by_project.setdefault(project.id, [])
            self.messages._by_project.setdefault(project.id, [])
            return deepcopy(project)

    def get_project(self, project_id) -> Project:
        with self._lock:
            return deepcopy(self._get_project_raw(project_id))

    def list_projects(self) -> List[Project]:
        with self._lock:
            items = sorted(self.projects._items.values(), key=lambda p: p.id)
            return [deepcopy(p) for p in items]

    def update_project(self, project_id, name=None, start_date=None, end_date=None, description=None) -> Project:
        with self._lock:
            project = self._get_project_raw(project_id)

            if name is not None:
                self._validate_non_empty(name, "name")
            effective_start = start_date if start_date is not None else project.start_date
            effective_end = end_date if end_date is not None else project.end_date
            if effective_end < effective_start:
                raise ValidationError("end_date cannot precede start_date")

            if name is not None:
                project.name = name
            if start_date is not None:
                project.start_date = start_date
            if end_date is not None:
                project.end_date = end_date
            if description is not None:
                project.description = description
            return deepcopy(project)

    def delete_project(self, project_id) -> None:
        with self._lock:
            self._get_project_raw(project_id)

            for tid in list(self.tasks._by_project.get(project_id, [])):
                task = self.tasks._items.get(tid)
                if task is not None:
                    self._purge_task(task)
            self.tasks._by_project.pop(project_id, None)

            for mid in list(self.messages._by_project.get(project_id, [])):
                self._purge_message(mid)
            self.messages._by_project.pop(project_id, None)

            del self.projects._items[project_id]

    # ------------------------------------------------------------------
    # Task management
    # ------------------------------------------------------------------
    def create_task(self, project_id, title, assignee_id=None, deadline=None) -> Task:
        with self._lock:
            project = self._get_project_raw(project_id)
            self._validate_non_empty(title, "title")
            if assignee_id is not None:
                self._get_user_raw(assignee_id)
            if deadline is not None and deadline < project.start_date:
                raise ValidationError("deadline cannot precede project start")

            task = Task(
                id=self._next_id(),
                project_id=project_id,
                title=title,
                status=TaskStatus.NOT_STARTED,
                assignee_id=None,
                deadline=deadline,
                created_at=self._clock(),
            )
            self.tasks._items[task.id] = task
            self.tasks._by_project.setdefault(project_id, []).append(task.id)
            if assignee_id is not None:
                self._set_assignee(task, assignee_id)
            return deepcopy(task)

    def get_task(self, task_id) -> Task:
        with self._lock:
            return deepcopy(self._get_task_raw(task_id))

    def list_tasks_by_project(self, project_id) -> List[Task]:
        with self._lock:
            self._get_project_raw(project_id)
            ids = self.tasks._by_project.get(project_id, [])
            items = sorted((self.tasks._items[i] for i in ids), key=lambda t: t.id)
            return [deepcopy(t) for t in items]

    def list_tasks_by_assignee(self, user_id) -> List[Task]:
        with self._lock:
            self._get_user_raw(user_id)
            ids = self.tasks._by_assignee.get(user_id, [])
            items = sorted((self.tasks._items[i] for i in ids), key=lambda t: t.id)
            return [deepcopy(t) for t in items]

    def assign_task(self, task_id, assignee_id) -> Task:
        with self._lock:
            task = self._get_task_raw(task_id)
            self._get_user_raw(assignee_id)
            self._set_assignee(task, assignee_id)
            return deepcopy(task)

    def reassign_task(self, task_id, new_assignee_id) -> Task:
        with self._lock:
            task = self._get_task_raw(task_id)
            self._get_user_raw(new_assignee_id)
            self._set_assignee(task, new_assignee_id)
            return deepcopy(task)

    def unassign_task(self, task_id) -> Task:
        with self._lock:
            task = self._get_task_raw(task_id)
            self._set_assignee(task, None)
            return deepcopy(task)

    def set_deadline(self, task_id, deadline) -> Task:
        with self._lock:
            task = self._get_task_raw(task_id)
            if deadline is not None:
                project = self._get_project_raw(task.project_id)
                if deadline < project.start_date:
                    raise ValidationError("deadline cannot precede project start")
            task.deadline = deadline
            return deepcopy(task)

    def update_status(self, task_id, status) -> Task:
        with self._lock:
            task = self._get_task_raw(task_id)
            if not isinstance(status, TaskStatus):
                raise ValidationError("status must be a TaskStatus")

            now = self._clock()
            if status == TaskStatus.IN_PROGRESS:
                if task.started_at is None:
                    task.started_at = now
                task.completed_at = None
            elif status == TaskStatus.COMPLETED:
                if task.started_at is None:
                    task.started_at = now
                task.completed_at = now
            elif status == TaskStatus.NOT_STARTED:
                task.started_at = None
                task.completed_at = None
            task.status = status
            return deepcopy(task)

    # ------------------------------------------------------------------
    # Messaging
    # ------------------------------------------------------------------
    def post_message(self, author_id, body, project_id=None, task_id=None,
                     parent_id=None, attachments=None) -> Message:
        with self._lock:
            self._get_user_raw(author_id)

            targets = [t for t in (project_id, task_id) if t is not None]
            if len(targets) != 1:
                raise ValidationError("exactly one of project_id or task_id required")

            if project_id is not None:
                self._get_project_raw(project_id)
            if task_id is not None:
                self._get_task_raw(task_id)

            has_body = isinstance(body, str) and body.strip() != ""
            has_attachments = bool(attachments)
            if not has_body and not has_attachments:
                raise ValidationError("message requires a body or an attachment")

            if parent_id is not None:
                self._get_message_raw(parent_id)

            now = self._clock()
            built = self._build_attachments(attachments, author_id, now)

            message = Message(
                id=self._next_id(),
                author_id=author_id,
                body=body,
                project_id=project_id,
                task_id=task_id,
                parent_id=parent_id,
                attachments=built,
                created_at=now,
                edited_at=None,
            )
            self.messages._items[message.id] = message
            if project_id is not None:
                self.messages._by_project.setdefault(project_id, []).append(message.id)
            if task_id is not None:
                self.messages._by_task.setdefault(task_id, []).append(message.id)
            return deepcopy(message)

    def _build_attachments(self, attachments, uploader_id, when) -> List[Attachment]:
        result: List[Attachment] = []
        if not attachments:
            return result
        for entry in attachments:
            filename, data = entry
            self._validate_non_empty(filename, "filename")
            result.append(
                Attachment(
                    filename=filename,
                    size=len(data),
                    uploaded_by=uploader_id,
                    uploaded_at=when,
                )
            )
        return result

    def edit_message(self, message_id, editor_id, new_body) -> Message:
        with self._lock:
            message = self._get_message_raw(message_id)
            if message.author_id != editor_id:
                raise AuthorizationError("only the author may edit a message")
            self._validate_non_empty(new_body, "body")
            message.body = new_body
            message.edited_at = self._clock()
            return deepcopy(message)

    def add_attachment(self, message_id, user_id, filename, data) -> Message:
        with self._lock:
            message = self._get_message_raw(message_id)
            if message.author_id != user_id:
                raise AuthorizationError("only the author may add attachments")
            self._validate_non_empty(filename, "filename")
            message.attachments.append(
                Attachment(
                    filename=filename,
                    size=len(data),
                    uploaded_by=user_id,
                    uploaded_at=self._clock(),
                )
            )
            return deepcopy(message)

    def list_messages_by_project(self, project_id) -> List[Message]:
        with self._lock:
            self._get_project_raw(project_id)
            ids = self.messages._by_project.get(project_id, [])
            items = sorted((self.messages._items[i] for i in ids), key=lambda m: m.id)
            return [deepcopy(m) for m in items]

    def list_messages_by_task(self, task_id) -> List[Message]:
        with self._lock:
            self._get_task_raw(task_id)
            ids = self.messages._by_task.get(task_id, [])
            items = sorted((self.messages._items[i] for i in ids), key=lambda m: m.id)
            return [deepcopy(m) for m in items]

    def delete_message(self, message_id, user_id) -> None:
        with self._lock:
            message = self._get_message_raw(message_id)
            if message.author_id != user_id:
                raise AuthorizationError("only the author may delete a message")
            self._purge_message(message_id)

    # ------------------------------------------------------------------
    # Performance dashboard
    # ------------------------------------------------------------------
    def _assigned_tasks(self, user_id) -> List[Task]:
        ids = self.tasks._by_assignee.get(user_id, [])
        return [self.tasks._items[i] for i in ids if i in self.tasks._items]

    def get_completion_rate(self, user_id) -> float:
        with self._lock:
            self._get_user_raw(user_id)
            tasks = self._assigned_tasks(user_id)
            if not tasks:
                return 0.0
            completed = sum(1 for t in tasks if t.status == TaskStatus.COMPLETED)
            return completed / len(tasks)

    def get_average_completion_time(self, user_id) -> Optional[float]:
        with self._lock:
            self._get_user_raw(user_id)
            durations = self._completion_durations(self._assigned_tasks(user_id))
            if not durations:
                return None
            return sum(durations) / len(durations)

    @staticmethod
    def _completion_durations(tasks) -> List[float]:
        durations = []
        for t in tasks:
            if (
                t.status == TaskStatus.COMPLETED
                and t.started_at is not None
                and t.completed_at is not None
            ):
                durations.append((t.completed_at - t.started_at).total_seconds())
        return durations

    def submit_rating(self, rater_id, ratee_id, score, feedback="", task_id=None) -> Rating:
        with self._lock:
            if rater_id == ratee_id:
                raise ConflictError("cannot rate yourself")
            if not isinstance(score, int) or isinstance(score, bool):
                raise ValidationError("score must be an integer")
            if score < 1 or score > 5:
                raise ValidationError("score must be between 1 and 5")
            self._get_user_raw(rater_id)
            self._get_user_raw(ratee_id)
            if task_id is not None:
                self._get_task_raw(task_id)

            rating = Rating(
                id=self._next_id(),
                rater_id=rater_id,
                ratee_id=ratee_id,
                score=score,
                feedback=feedback,
                task_id=task_id,
                created_at=self._clock(),
            )
            self.performance._items[rating.id] = rating
            self.performance._by_ratee.setdefault(ratee_id, []).append(rating.id)
            return deepcopy(rating)

    def _ratings_for(self, user_id) -> List[Rating]:
        ids = self.performance._by_ratee.get(user_id, [])
        items = [self.performance._items[i] for i in ids if i in self.performance._items]
        return sorted(items, key=lambda r: r.id)

    def get_ratings_summary(self, user_id) -> Dict[str, Any]:
        with self._lock:
            self._get_user_raw(user_id)
            ratings = self._ratings_for(user_id)
            count = len(ratings)
            average = sum(r.score for r in ratings) / count if count else 0.0
            return {
                "count": count,
                "average": average,
                "ratings": [deepcopy(r) for r in ratings],
            }

    def get_user_dashboard(self, user_id) -> Dict[str, Any]:
        with self._lock:
            self._get_user_raw(user_id)
            tasks = self._assigned_tasks(user_id)
            total = len(tasks)
            completed = sum(1 for t in tasks if t.status == TaskStatus.COMPLETED)
            in_progress = sum(1 for t in tasks if t.status == TaskStatus.IN_PROGRESS)
            not_started = sum(1 for t in tasks if t.status == TaskStatus.NOT_STARTED)
            durations = self._completion_durations(tasks)
            avg_time = sum(durations) / len(durations) if durations else None
            ratings = self._ratings_for(user_id)
            rating_count = len(ratings)
            rating_average = (
                sum(r.score for r in ratings) / rating_count if rating_count else 0.0
            )
            return {
                "user_id": user_id,
                "total_tasks": total,
                "completed_tasks": completed,
                "in_progress_tasks": in_progress,
                "not_started_tasks": not_started,
                "completion_rate": completed / total if total else 0.0,
                "average_completion_time": avg_time,
                "rating_count": rating_count,
                "rating_average": rating_average,
            }

    # ------------------------------------------------------------------
    # Reports
    # ------------------------------------------------------------------
    def project_progress_report(self, project_id) -> Dict[str, Any]:
        with self._lock:
            project = self._get_project_raw(project_id)
            ids = self.tasks._by_project.get(project_id, [])
            tasks = [self.tasks._items[i] for i in ids if i in self.tasks._items]
            total = len(tasks)
            status_counts = {status.value: 0 for status in TaskStatus}
            completed = 0
            overdue = 0
            per_assignee: Dict[int, Dict[str, Any]] = {}
            now = self._clock()
            for task in tasks:
                status_counts[task.status.value] += 1
                if task.status == TaskStatus.COMPLETED:
                    completed += 1
                if (
                    task.deadline is not None
                    and task.status != TaskStatus.COMPLETED
                    and task.deadline < now
                ):
                    overdue += 1
                if task.assignee_id is not None:
                    bucket = per_assignee.setdefault(
                        task.assignee_id, {"total": 0, "completed": 0}
                    )
                    bucket["total"] += 1
                    if task.status == TaskStatus.COMPLETED:
                        bucket["completed"] += 1
            return {
                "report_type": ReportType.PROJECT_PROGRESS.value,
                "project_id": project_id,
                "project_name": project.name,
                "total_tasks": total,
                "status_counts": status_counts,
                "completion_rate": completed / total if total else 0.0,
                "overdue_tasks": overdue,
                "per_assignee": per_assignee,
            }

    def _performance_row(self, user_id, project_id) -> Dict[str, Any]:
        user = self.users._items[user_id]
        tasks = self._assigned_tasks(user_id)
        if project_id is not None:
            tasks = [t for t in tasks if t.project_id == project_id]
        total = len(tasks)
        completed = sum(1 for t in tasks if t.status == TaskStatus.COMPLETED)
        durations = self._completion_durations(tasks)
        avg_time = sum(durations) / len(durations) if durations else None
        ratings = self._ratings_for(user_id)
        rating_count = len(ratings)
        rating_average = (
            sum(r.score for r in ratings) / rating_count if rating_count else 0.0
        )
        return {
            "user_id": user_id,
            "username": user.username,
            "total_tasks": total,
            "completed_tasks": completed,
            "completion_rate": completed / total if total else 0.0,
            "average_completion_time": avg_time,
            "rating_count": rating_count,
            "rating_average": rating_average,
        }

    def team_performance_report(self, project_id=None) -> Dict[str, Any]:
        with self._lock:
            if project_id is not None:
                self._get_project_raw(project_id)
                ids = self.tasks._by_project.get(project_id, [])
                user_ids = sorted(
                    {
                        self.tasks._items[i].assignee_id
                        for i in ids
                        if i in self.tasks._items
                        and self.tasks._items[i].assignee_id is not None
                    }
                )
            else:
                user_ids = sorted(self.users._items.keys())
            rows = [self._performance_row(uid, project_id) for uid in user_ids]
            return {
                "report_type": ReportType.TEAM_PERFORMANCE.value,
                "project_id": project_id,
                "rows": rows,
            }

    def individual_performance_report(self, user_id) -> Dict[str, Any]:
        with self._lock:
            user = self._get_user_raw(user_id)
            tasks = sorted(self._assigned_tasks(user_id), key=lambda t: t.id)
            total = len(tasks)
            completed = sum(1 for t in tasks if t.status == TaskStatus.COMPLETED)
            durations = self._completion_durations(tasks)
            avg_time = sum(durations) / len(durations) if durations else None
            task_rows = [
                {
                    "task_id": t.id,
                    "title": t.title,
                    "status": t.status.value,
                    "project_id": t.project_id,
                }
                for t in tasks
            ]
            return {
                "report_type": ReportType.INDIVIDUAL_PERFORMANCE.value,
                "user_id": user_id,
                "username": user.username,
                "total_tasks": total,
                "completed_tasks": completed,
                "average_completion_time": avg_time,
                "tasks": task_rows,
            }

    # ------------------------------------------------------------------
    # Report export
    # ------------------------------------------------------------------
    def export_report(self, report, fmt):
        if not isinstance(fmt, ReportFormat):
            raise ValidationError("fmt must be a ReportFormat")
        if not isinstance(report, dict):
            raise ValidationError("report must be a dict")
        if fmt == ReportFormat.CSV:
            return self._report_to_csv(report)
        return self._report_to_pdf(report)

    @staticmethod
    def _csv_value(value) -> str:
        if value is None:
            return ""
        if isinstance(value, (dict, list, tuple)):
            return str(value)
        return value if isinstance(value, str) else str(value)

    def _report_to_csv(self, report) -> str:
        out = io.StringIO()
        rows = report.get("rows")
        if isinstance(rows, list) and rows and all(isinstance(r, dict) for r in rows):
            fieldnames: List[str] = []
            for row in rows:
                for key in row.keys():
                    if key not in fieldnames:
                        fieldnames.append(key)
            writer = csv.writer(out)
            writer.writerow(fieldnames)
            for row in rows:
                writer.writerow([self._csv_value(row.get(k)) for k in fieldnames])
        else:
            writer = csv.writer(out)
            writer.writerow(["field", "value"])
            for key, value in report.items():
                writer.writerow([key, self._csv_value(value)])
        return out.getvalue()

    def _report_to_pdf(self, report) -> bytes:
        return self._build_pdf(self._report_to_lines(report))

    @staticmethod
    def _report_to_lines(report) -> List[str]:
        lines = ["Report: {0}".format(report.get("report_type", "report"))]
        for key, value in report.items():
            if key == "report_type":
                continue
            if key == "rows" and isinstance(value, list):
                lines.append("rows:")
                for row in value:
                    if isinstance(row, dict):
                        lines.append(
                            "  "
                            + ", ".join(
                                "{0}={1}".format(k, v) for k, v in row.items()
                            )
                        )
                    else:
                        lines.append("  {0}".format(row))
            elif key == "tasks" and isinstance(value, list):
                lines.append("tasks:")
                for row in value:
                    lines.append("  {0}".format(row))
            else:
                lines.append("{0}: {1}".format(key, value))
        return lines

    @staticmethod
    def _build_pdf(lines) -> bytes:
        """Render a minimal but structurally valid single-page PDF document."""

        def encode(text):
            return text.encode("latin-1", "replace")

        text_ops = ["BT", "/F1 11 Tf", "54 760 Td", "14 TL"]
        for line in lines:
            safe = (
                str(line)
                .replace("\\", "\\\\")
                .replace("(", "\\(")
                .replace(")", "\\)")
            )
            if len(safe) > 110:
                safe = safe[:110]
            text_ops.append("({0}) Tj".format(safe))
            text_ops.append("T*")
        text_ops.append("ET")
        content = encode("\n".join(text_ops))

        bodies = [
            b"<< /Type /Catalog /Pages 2 0 R >>",
            b"<< /Type /Pages /Kids [3 0 R] /Count 1 >>",
            b"<< /Type /Page /Parent 2 0 R /MediaBox [0 0 612 792] "
            b"/Resources << /Font << /F1 4 0 R >> >> /Contents 5 0 R >>",
            b"<< /Type /Font /Subtype /Type1 /BaseFont /Helvetica >>",
            b"<< /Length "
            + str(len(content)).encode("latin-1")
            + b" >>\nstream\n"
            + content
            + b"\nendstream",
        ]

        out = bytearray(b"%PDF-1.4\n")
        offsets = []
        for index, body in enumerate(bodies, start=1):
            offsets.append(len(out))
            out += "{0} 0 obj\n".format(index).encode("latin-1")
            out += body
            out += b"\nendobj\n"

        xref_pos = len(out)
        size = len(bodies) + 1
        out += "xref\n0 {0}\n".format(size).encode("latin-1")
        out += b"0000000000 65535 f \n"
        for offset in offsets:
            out += "{0:010d} 00000 n \n".format(offset).encode("latin-1")
        out += "trailer\n<< /Size {0} /Root 1 0 R >>\n".format(size).encode("latin-1")
        out += b"startxref\n"
        out += "{0}\n".format(xref_pos).encode("latin-1")
        out += b"%%EOF"
        return bytes(out)
